@page "/settings"
@using sv_ef85edd4d3e948ee8af632d80cf950f0.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <h4 class="sidebar-title">Settings</h4>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li class="@(ActiveSection == section.Key ? "active" : "")"
                    @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="toast-message @_toastType">
                    @_toastMessage
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ────────── Profile ────────── *@
@{
    RenderFragment RenderProfileSection() =>
        @<div class="section-panel">
            <h3>Profile Settings</h3>
            <p class="section-desc">Manage your public profile information.</p>

            <div class="avatar-area">
                <img src="@_editProfile!.AvatarUrl" alt="Avatar" class="avatar-img" />
                <span class="avatar-url">@_editProfile.AvatarUrl</span>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" class="form-control" @bind="_editProfile.DisplayName" />
            </div>
            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" class="form-control" @bind="_editProfile.Email" />
            </div>
            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" class="form-control" rows="4" @bind="_editProfile.Bio"></textarea>
            </div>

            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </div>;
}

@* ────────── Notifications ────────── *@
@{
    RenderFragment RenderNotificationsSection() =>
        @<div class="section-panel">
            <h3>Notification Preferences</h3>
            <p class="section-desc">Control how and when you receive notifications.</p>

            <div class="toggle-row">
                <label class="toggle-label">
                    <span>Email Notifications</span>
                    <input type="checkbox" class="form-check-input toggle-switch" @bind="_editNotifications!.EmailNotifications" />
                </label>
            </div>
            <div class="toggle-row">
                <label class="toggle-label">
                    <span>Push Notifications</span>
                    <input type="checkbox" class="form-check-input toggle-switch" @bind="_editNotifications.PushNotifications" />
                </label>
            </div>
            <div class="toggle-row">
                <label class="toggle-label">
                    <span>Weekly Digest</span>
                    <input type="checkbox" class="form-check-input toggle-switch" @bind="_editNotifications.WeeklyDigest" />
                </label>
            </div>

            <h5 class="mt-4">Muted Channels</h5>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var isMuted = _editNotifications.MutedChannels.Contains(channel);
                    <label class="channel-item">
                        <input type="checkbox" class="form-check-input"
                               checked="@isMuted"
                               @onchange="(e) => ToggleMutedChannel(channel, (bool)e.Value!)" />
                        <span>#@channel</span>
                        <span class="badge @(isMuted ? "bg-secondary" : "bg-success")">@(isMuted ? "Muted" : "Active")</span>
                    </label>
                }
            </div>

            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveNotifications">Save Preferences</button>
            </div>
        </div>;
}

@* ────────── Security ────────── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<div class="section-panel">
            <h3>Security</h3>
            <p class="section-desc">Manage your password, two-factor authentication, and active sessions.</p>

            @* Change Password *@
            <div class="expandable-panel">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>🔑 Change Password</span>
                    <span class="chevron @(_passwordPanelOpen ? "open" : "")">▸</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="form-group">
                            <label for="currentPwd">Current Password</label>
                            <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label for="newPwd">New Password</label>
                            <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label for="confirmPwd">Confirm Password</label>
                            <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (!string.IsNullOrEmpty(_passwordError))
                        {
                            <div class="alert alert-danger">@_passwordError</div>
                        }
                        <button class="btn btn-warning" @onclick="UpdatePassword">Update Password</button>
                    </div>
                }
            </div>

            @* 2FA *@
            <div class="toggle-row mt-3">
                <label class="toggle-label">
                    <span>
                        Two-Factor Authentication
                        <span class="status-badge @(_securitySettings!.TwoFactorEnabled ? "enabled" : "disabled")">
                            @(_securitySettings.TwoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </span>
                    <input type="checkbox" class="form-check-input toggle-switch"
                           checked="@_securitySettings.TwoFactorEnabled"
                           disabled />
                </label>
            </div>
            @if (_securitySettings.LastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2">Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }

            @* Active Sessions *@
            <h5 class="mt-4">Active Sessions</h5>
            <div class="table-responsive">
                <table class="table table-hover">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _securitySettings.Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != CurrentSessionId)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevokeSession(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>

            @* Revoke Confirmation Dialog *@
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop" @onclick="() => _sessionToRevoke = null">
                    <div class="confirm-dialog" @onclick:stopPropagation>
                        <h5>Revoke Session</h5>
                        <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                        <div class="button-row">
                            <button class="btn btn-danger" @onclick="ConfirmRevokeSession">Revoke</button>
                            <button class="btn btn-outline-secondary" @onclick="() => _sessionToRevoke = null">Cancel</button>
                        </div>
                    </div>
                </div>
            }
        </div>;
}

@* ────────── Appearance ────────── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<div class="section-panel">
            <h3>Appearance</h3>
            <p class="section-desc">Customize the look and feel of the application.</p>

            <div class="form-group">
                <label><strong>Theme</strong></label>
                <div class="radio-group">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <label class="radio-item">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_editAppearance!.Theme == theme)"
                                   @onchange="() => _editAppearance!.Theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label><strong>Font Size</strong></label>
                <div class="radio-group">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <label class="radio-item">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_editAppearance!.FontSize == size)"
                                   @onchange="() => _editAppearance!.FontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label for="language"><strong>Language</strong></label>
                <select id="language" class="form-select" @bind="_editAppearance!.Language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="toggle-row">
                <label class="toggle-label">
                    <span><strong>Compact Mode</strong></span>
                    <input type="checkbox" class="form-check-input toggle-switch" @bind="_editAppearance.CompactMode" />
                </label>
            </div>

            @* Live Preview *@
            <div class="preview-area @GetPreviewClasses()">
                <h6>Live Preview</h6>
                <p>This is how your content will look with the selected settings.</p>
                <button class="btn @(_editAppearance.Theme == "Dark" ? "btn-light" : "btn-primary") btn-sm">Sample Button</button>
                <span class="badge bg-secondary ms-2">Badge</span>
            </div>

            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </div>;
}

@code {
    // ── Section navigation ──
    private record SectionMeta(string Label, string Icon);

    private readonly Dictionary<string, SectionMeta> _sections = new()
    {
        ["profile"] = new("Profile", "👤"),
        ["notifications"] = new("Notifications", "🔔"),
        ["security"] = new("Security", "🔒"),
        ["appearance"] = new("Appearance", "🎨"),
    };

    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // ── Toast ──
    private string? _toastMessage;
    private string _toastType = "success";
    private CancellationTokenSource? _toastCts;

    // ── Profile ──
    private ProfileEdit? _editProfile;
    private UserProfile? _savedProfile;

    // ── Notifications ──
    private NotificationEdit? _editNotifications;
    private readonly List<string> _allChannels = ["announcements", "random", "off-topic", "dev-alerts", "design"];

    // ── Security ──
    private SecuritySettings? _securitySettings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private ActiveSession? _sessionToRevoke;
    private const string CurrentSessionId = "sess-1";

    // ── Appearance ──
    private AppearanceEdit? _editAppearance;
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    // ── Mutable wrappers for binding ──
    private class ProfileEdit
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";

        public static ProfileEdit From(UserProfile p) =>
            new() { DisplayName = p.DisplayName, Email = p.Email, AvatarUrl = p.AvatarUrl, Bio = p.Bio };

        public UserProfile ToRecord() => new(DisplayName, Email, AvatarUrl, Bio);
    }

    private class NotificationEdit
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public List<string> MutedChannels { get; set; } = [];

        public static NotificationEdit From(NotificationPrefs p) =>
            new()
            {
                EmailNotifications = p.EmailNotifications,
                PushNotifications = p.PushNotifications,
                WeeklyDigest = p.WeeklyDigest,
                MutedChannels = [.. p.MutedChannels],
            };

        public NotificationPrefs ToRecord() => new(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; } = "Light";
        public string FontSize { get; set; } = "Medium";
        public string Language { get; set; } = "English";
        public bool CompactMode { get; set; }

        public static AppearanceEdit From(AppearanceSettings a) =>
            new() { Theme = a.Theme, FontSize = a.FontSize, Language = a.Language, CompactMode = a.CompactMode };

        public AppearanceSettings ToRecord() => new(Theme, FontSize, Language, CompactMode);
    }

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        _editProfile = ProfileEdit.From(profile);

        var notifs = await SettingsService.GetNotificationPrefsAsync();
        _editNotifications = NotificationEdit.From(notifs);

        _securitySettings = await SettingsService.GetSecuritySettingsAsync();

        var appearance = await SettingsService.GetAppearanceAsync();
        _editAppearance = AppearanceEdit.From(appearance);

        _loading = false;
    }

    // ── Profile actions ──
    private async Task SaveProfile()
    {
        var record = _editProfile!.ToRecord();
        await SettingsService.SaveProfileAsync(record);
        _savedProfile = record;
        await ShowToast("Profile saved successfully.", "success");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            _editProfile = ProfileEdit.From(_savedProfile);
    }

    // ── Notification actions ──
    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted && !_editNotifications!.MutedChannels.Contains(channel))
            _editNotifications.MutedChannels.Add(channel);
        else if (!muted)
            _editNotifications!.MutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        await SettingsService.SaveNotificationPrefsAsync(_editNotifications!.ToRecord());
        await ShowToast("Notification preferences saved.", "success");
    }

    // ── Security actions ──
    private async Task UpdatePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = _newPassword = _confirmPassword = "";
        _passwordPanelOpen = false;
        await ShowToast("Password updated successfully.", "success");
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        await ShowToast("Session revoked.", "success");
    }

    // ── Appearance actions ──
    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_editAppearance!.Theme == "Dark") classes.Add("preview-dark");
        else classes.Add("preview-light");
        classes.Add($"preview-font-{_editAppearance.FontSize.ToLowerInvariant()}");
        if (_editAppearance.CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        await SettingsService.SaveAppearanceAsync(_editAppearance!.ToRecord());
        await ShowToast("Appearance settings saved.", "success");
    }

    // ── Toast helper ──
    private async Task ShowToast(string message, string type)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _toastMessage = message;
        _toastType = type;
        StateHasChanged();

        try
        {
            await Task.Delay(3000, _toastCts.Token);
            _toastMessage = null;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

/* ── Layout ── */
.settings-container {
    display: flex;
    min-height: 80vh;
    gap: 0;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.25rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
    color: #495057;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.sidebar-nav li {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    font-size: 0.95rem;
    color: #495057;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-nav li:hover {
    background: #e9ecef;
}

.sidebar-nav li.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.1rem;
}

/* ── Content ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
}

.section-panel h3 {
    margin: 0 0 0.25rem;
    font-size: 1.4rem;
}

.section-desc {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

/* ── Toast ── */
.toast-message {
    position: absolute;
    top: 1rem;
    right: 1rem;
    padding: 0.6rem 1.2rem;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    z-index: 100;
    animation: toast-slide-in 0.25s ease-out;
}

.toast-message.success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-message.error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

@keyframes toast-slide-in {
    from { opacity: 0; transform: translateY(-10px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Loading ── */
.loading-spinner {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 200px;
}

/* ── Form elements ── */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
    color: #212529;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

/* ── Avatar ── */
.avatar-area {
    display: flex;
    align-items: center;
    gap: 1rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.avatar-img {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-url {
    font-size: 0.85rem;
    color: #6c757d;
    word-break: break-all;
}

/* ── Toggle rows ── */
.toggle-row {
    padding: 0.6rem 0;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-label {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    margin: 0;
    width: 100%;
}

.toggle-switch {
    width: 2.5em !important;
    height: 1.25em;
    cursor: pointer;
}

/* ── Channel list ── */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.5rem 0.75rem;
    background: #f8f9fa;
    border-radius: 6px;
    cursor: pointer;
    margin: 0;
}

.channel-item .badge {
    margin-left: auto;
    font-size: 0.75rem;
}

/* ── Expandable panel ── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
}

.expandable-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 0.95rem;
    font-weight: 500;
}

.expandable-header:hover {
    background: #e9ecef;
}

.chevron {
    transition: transform 0.2s;
    font-size: 0.85rem;
}

.chevron.open {
    transform: rotate(90deg);
}

.expandable-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ── Status badge ── */
.status-badge {
    font-size: 0.75rem;
    padding: 0.15rem 0.5rem;
    border-radius: 10px;
    margin-left: 0.5rem;
    font-weight: 600;
}

.status-badge.enabled {
    background: #d1e7dd;
    color: #0f5132;
}

.status-badge.disabled {
    background: #f8d7da;
    color: #842029;
}

/* ── Confirmation dialog ── */
.modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.4);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.confirm-dialog {
    background: #fff;
    border-radius: 10px;
    padding: 1.5rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

.confirm-dialog h5 {
    margin: 0 0 0.75rem;
}

/* ── Appearance radio group ── */
.radio-group {
    display: flex;
    gap: 1.25rem;
    margin-top: 0.3rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    cursor: pointer;
    margin: 0;
}

/* ── Live preview ── */
.preview-area {
    margin-top: 1.5rem;
    padding: 1.25rem;
    border: 2px dashed #dee2e6;
    border-radius: 8px;
    transition: all 0.3s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #212529;
    color: #f8f9fa;
    border-color: #495057;
}

.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

.preview-compact {
    padding: 0.6rem;
    line-height: 1.2;
}

.preview-compact p {
    margin-bottom: 0.25rem;
}

/* ── Table tweaks ── */
.table th {
    font-size: 0.85rem;
    text-transform: uppercase;
    color: #6c757d;
    font-weight: 600;
}

