+    to   { opacity: 1; transform: translateY(0); }
+}
+
+/* ── Loading ── */
+.loading-spinner {
+    display: flex;
+    justify-content: center;
+    align-items: center;
+    height: 200px;
+}
+
+/* ── Form elements ── */
+.form-group {
+    margin-bottom: 1rem;
+}
+
+.form-group label {
+    display: block;
+    margin-bottom: 0.3rem;
+    font-weight: 500;
+    color: #212529;
+}
+
+.button-row {
+    display: flex;
+    gap: 0.75rem;
+    margin-top: 1.5rem;
+}
+
+/* ── Avatar ── */
+.avatar-area {
+    display: flex;
+    align-items: center;
+    gap: 1rem;
+    margin-bottom: 1.5rem;
+    padding: 1rem;
+    background: #f8f9fa;
+    border-radius: 8px;
+}
+
+.avatar-img {
+    width: 80px;
+    height: 80px;
+    border-radius: 50%;
+    object-fit: cover;
+    border: 3px solid #dee2e6;
+}
+
+.avatar-url {
+    font-size: 0.85rem;
+    color: #6c757d;
+    word-break: break-all;
+}
+
+/* ── Toggle rows ── */
+.toggle-row {
+    padding: 0.6rem 0;
+    border-bottom: 1px solid #f0f0f0;
+}
+
+.toggle-label {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    cursor: pointer;
+    margin: 0;
+    width: 100%;
+}
+
+.toggle-switch {
+    width: 2.5em !important;
+    height: 1.25em;
+    cursor: pointer;
+}
+
+/* ── Channel list ── */
+.channel-list {
+    display: flex;
+    flex-direction: column;
+    gap: 0.4rem;
+}
+
+.channel-item {
+    display: flex;
+    align-items: center;
+    gap: 0.6rem;
+    padding: 0.5rem 0.75rem;
+    background: #f8f9fa;
+    border-radius: 6px;
+    cursor: pointer;
+    margin: 0;
+}
+
+.channel-item .badge {
+    margin-left: auto;
+    font-size: 0.75rem;
+}
+
+/* ── Expandable panel ── */
+.expandable-panel {
+    border: 1px solid #dee2e6;
+    border-radius: 8px;
+    overflow: hidden;
+}
+
+.expandable-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    width: 100%;
+    padding: 0.75rem 1rem;
+    background: #f8f9fa;
+    border: none;
+    cursor: pointer;
+    font-size: 0.95rem;
+    font-weight: 500;
+}
+
+.expandable-header:hover {
+    background: #e9ecef;
+}
+
+.chevron {
+    transition: transform 0.2s;
+    font-size: 0.85rem;
+}
+
+.chevron.open {
+    transform: rotate(90deg);
+}
+
+.expandable-body {
+    padding: 1rem;
+    border-top: 1px solid #dee2e6;
+}
+
+/* ── Status badge ── */
+.status-badge {
+    font-size: 0.75rem;
+    padding: 0.15rem 0.5rem;
+    border-radius: 10px;
+    margin-left: 0.5rem;
+    font-weight: 600;
+}
+
+.status-badge.enabled {
+    background: #d1e7dd;
+    color: #0f5132;
+}
+
+.status-badge.disabled {
+    background: #f8d7da;
+    color: #842029;
+}
+
+/* ── Confirmation dialog ── */
+.modal-backdrop {
+    position: fixed;
+    top: 0;
+    left: 0;
+    width: 100%;
+    height: 100%;
+    background: rgba(0, 0, 0, 0.4);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    z-index: 1050;
+}
+
+.confirm-dialog {
+    background: #fff;
+    border-radius: 10px;
+    padding: 1.5rem;
+    max-width: 420px;
+    width: 90%;
+    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
+}
+
+.confirm-dialog h5 {
+    margin: 0 0 0.75rem;
+}
+
+/* ── Appearance radio group ── */
+.radio-group {
+    display: flex;
+    gap: 1.25rem;
+    margin-top: 0.3rem;
+}
+
+.radio-item {
+    display: flex;
+    align-items: center;
+    gap: 0.35rem;
+    cursor: pointer;
+    margin: 0;
+}
+
+/* ── Live preview ── */
+.preview-area {
+    margin-top: 1.5rem;
+    padding: 1.25rem;
+    border: 2px dashed #dee2e6;
+    border-radius: 8px;
+    transition: all 0.3s ease;
+}
+
+.preview-light {
+    background: #ffffff;
+    color: #212529;
+}
+
+.preview-dark {
+    background: #212529;
+    color: #f8f9fa;
+    border-color: #495057;
+}
+
+.preview-font-small {
+    font-size: 0.8rem;
+}
+
+.preview-font-medium {
+    font-size: 1rem;
+}
+
+.preview-font-large {
+    font-size: 1.2rem;
+}
+
+.preview-compact {
+    padding: 0.6rem;
+    line-height: 1.2;
+}
+
+.preview-compact p {
+    margin-bottom: 0.25rem;
+}
+
+/* ── Table tweaks ── */
+.table th {
+    font-size: 0.85rem;
+    text-transform: uppercase;
+    color: #6c757d;
+    font-weight: 600;
+}
+

